  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index) VALUES
    (v_sop_id, 1, 'Objetivo', E'Garantir que os registros financeiros da TBO no OMIE estejam 100% alinhados com os extratos bancários reais.\n\nA conciliação bancária identifica divergências entre o que o banco registrou e o que está no sistema, eliminando erros que comprometeriam o DRE, o fluxo de caixa e as decisões financeiras da diretoria. Sem conciliação bancária, qualquer análise financeira parte de dados potencialmente incorretos.', 'step', 0),
    (v_sop_id, 2, 'Escopo', E'**Quem executa:** Líder Financeiro (execução) + Marco ou Ruy (validação final)\n**Quando se aplica:** Todo dia útil após o fechamento do mês anterior — prazo: até dia 5 do mês seguinte\n**Contas cobertas:** Todas as contas correntes e de aplicação da TBO\n**Não se aplica:** Cartões de crédito corporativos (processo separado), contas pessoais dos sócios', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Download dos extratos bancários | Líder Financeiro | — | — | — |\n| Exportação de lançamentos do OMIE | Líder Financeiro | — | — | — |\n| Cruzamento e identificação de divergências | Líder Financeiro | — | — | — |\n| Regularização de lançamentos pendentes | Líder Financeiro | Marco / Ruy | — | — |\n| Classificação de lançamentos sem categoria | Líder Financeiro | Marco | — | — |\n| Validação final | Marco ou Ruy | — | Líder Financeiro | — |\n| Arquivamento do relatório | Líder Financeiro | — | — | Marco / Ruy |\n| Alimentação do DRE pós-conciliação | Líder Financeiro | Marco | — | Ruy |', 'step', 2),
    (v_sop_id, 4, 'Pré-requisitos', E'- [ ] Acesso ao internet banking de todas as contas TBO\n- [ ] Acesso ao OMIE com permissão de exportação de relatórios\n- [ ] Acesso ao TBO OS (módulo Financeiro)\n- [ ] Planilha de conciliação do mês anterior (base de comparação)\n- [ ] Período de referência definido (dia 1 ao último dia do mês)\n- [ ] Extratos dos últimos 2 meses disponíveis (para checar lançamentos em trânsito)', 'step', 3),
    (v_sop_id, 5, 'Procedimento', E'**Preparação (Dia 1 após fechamento):**\n1. Baixar extratos bancários de todas as contas (formato OFX ou PDF)\n2. OMIE > Financeiro > Relatórios > Extrato de Movimentações — exportar o período em .xlsx\n3. Abrir planilha de conciliação; importar dados OMIE na aba "Sistema" e extrato na aba "Banco"\n\n**Cruzamento de Lançamentos:**\nPara cada lançamento do extrato bancário, localizar o correspondente no OMIE:\n- **Match perfeito**: data + valor + tipo idênticos → "Conciliado ✓"\n- **No banco, sem OMIE**: "Pendente — banco" (falta lançar no sistema)\n- **No OMIE, sem banco**: "Pendente — sistema" (possível erro de data ou duplicata)\n- **Valor divergente**: "Divergência de valor — investigar"\n\n**Regularização de Divergências:**\n- **Banco sem OMIE**: criar lançamento com categoria correta; se desconhecido, escalar\n- **OMIE sem banco**: verificar se está em trânsito; se não aparecer no próximo mês, investigar duplicata\n- **Divergência de valor**: verificar taxa bancária, desconto de boleto; corrigir no OMIE com nota\n- **Sem categoria**: consultar NF correspondente; NUNCA classificar como "outros" sem investigação\n\n**Validação e Fechamento:**\n1. Saldo final banco = saldo final OMIE (após regularizações)\n2. Se ainda houver diferença: investigar até zerar — não fechar com divergência\n3. Preencher Relatório de Conciliação (ver Template Anexo)\n4. Enviar para Marco/Ruy via TBO OS para validação\n5. Após validação: arquivar em `Drive > Financeiro > Conciliacao > [Ano] > [Mês]`\n6. Verificar categorias do OMIE; exportar DRE e comparar com previsto; atualizar TBO OS', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'**Durante a conciliação:**\n- [ ] Extratos de todas as contas baixados\n- [ ] Exportação OMIE feita para o período completo\n- [ ] 100% dos lançamentos classificados (sem item em branco)\n- [ ] Saldo final banco = saldo final OMIE\n- [ ] Lançamentos em trânsito documentados e justificados\n- [ ] Todas as divergências resolvidas (ou escaladas)\n- [ ] Relatório de conciliação preenchido\n\n**Após conciliação:**\n- [ ] Relatório enviado para validação de Marco ou Ruy\n- [ ] Relatório arquivado no Drive\n- [ ] DRE exportado e comparado com previsto\n- [ ] Dashboard financeiro TBO OS atualizado\n- [ ] Prazo respeitado (até dia 5 do mês seguinte)', 'checkpoint', 5),
    (v_sop_id, 7, 'Ferramentas e Recursos', E'- **OMIE**: módulo Financeiro > Relatórios > Extrato de Movimentações\n- **Internet Banking**: acesso às contas TBO (credenciais no cofre de senhas — 1Password)\n- **Planilha de Conciliação**: `Drive > Financeiro > Templates > Conciliacao-Bancaria.xlsx`\n- **TBO OS**: módulo Financeiro > Dashboard para atualização de saldos\n- **Drive**: `Financeiro > Conciliacao > [Ano] > [Mês]` para arquivamento\n- **1Password**: cofre de senhas para credenciais bancárias (acesso restrito a líderes autorizados)', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'| Etapa | SLA |\n|---|---|\n| Início da conciliação | Até dia 2 do mês seguinte |\n| Conclusão e envio para validação | Até dia 4 do mês seguinte |\n| Validação por Marco/Ruy | Até dia 5 do mês seguinte |\n| Arquivamento final | Até dia 5 do mês seguinte |\n| Taxa de divergências | Meta: ≤ 2% do volume de lançamentos |\n| Saldo banco vs. OMIE ao fechar | Meta: R$ 0,00 de diferença |\n| Lançamentos sem categoria | Meta: 0 ao fechar |', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**Saldo final não fecha:**\n→ Verificar se todos os extratos do período foram importados\n→ Conferir lançamentos duplicados no OMIE (mesmo valor + data próxima)\n→ Verificar se há depósitos de juros ou IOF não lançados\n→ Se diferença > R$100: escalar imediatamente para Marco/Ruy\n\n**Lançamento desconhecido no extrato:**\n→ Consultar o banco (SAC) para identificar o histórico\n→ Cruzar com notas fiscais e contratos do período\n→ Nunca classificar como "outros" sem investigação — pode ser fraude ou erro bancário\n\n**OMIE com saldo diferente do extrato bancário:**\n→ Verificar se a conta no OMIE está configurada com o número correto\n→ Verificar se import automático de extrato está ativo e com atraso\n→ Desativar import automático temporariamente e reconciliar manualmente\n\n**Prazo não será cumprido (acima do dia 5):**\n→ Comunicar imediatamente Marco/Ruy com estimativa de conclusão\n→ Documentar o motivo do atraso para prevenir na próxima vez\n→ Priorizar conciliação sobre outras atividades financeiras', 'warning', 8),
    (v_sop_id, 10, 'Template Anexo', E'**Relatório de Conciliação Bancária**\n```\nRELATÓRIO DE CONCILIAÇÃO BANCÁRIA\nMês/Ano: ___  Conta: ___  Elaborado por: ___  Data: ___\n\nSALDOS:\n| Item | Banco (R$) | OMIE (R$) | Diferença (R$) |\n|---|---|---|---|\n| Saldo inicial | ___ | ___ | ___ |\n| (+) Entradas | ___ | ___ | ___ |\n| (-) Saídas | ___ | ___ | ___ |\n| Saldo final | ___ | ___ | ___ |\n\nLANÇAMENTOS EM TRÂNSITO:\n| Data | Descrição | Valor | Status |\n|---|---|---|---|\n| ___ | ___ | ___ | A conciliar no próximo mês |\n\nDIVERGÊNCIAS ENCONTRADAS E RESOLUÇÕES:\n| # | Descrição | Valor | Causa | Resolução |\n|---|---|---|---|---|\n| 1 | ___ | ___ | ___ | ___ |\n\nSTATUS FINAL:\n[ ] CONCILIADO — saldo banco = saldo OMIE\n[ ] CONCILIADO COM TRÂNSITO — diferença justificada: R$ ___\n[ ] PENDENTE — divergência não resolvida: R$ ___\n\nValidado por: ___  Data: ___  Assinatura: ___\n```', 'tip', 9);

